(function() {
  // Try to get thumbnail from ytInitialPlayerResponse
  var data = document.getElementById('yt-initial-player-response') || document.getElementById('yt-player-data');
  if (data) {
    try {
      var json = JSON.parse(data.textContent || data.innerText || data.innerHTML);
      if (json && json.videoDetails && json.videoDetails.thumbnail) {
        return {source: 'ytInitialPlayerResponse', thumbnails: json.videoDetails.thumbnail};
      }
    } catch(e) {}
  }
  // Try meta tags
  var meta = document.querySelector('meta[property="og:image"]');
  if (meta) {
    return {source: 'og:image', url: meta.content};
  }
  // Fallback: construct from video ID
  var videoId = new URLSearchParams(window.location.search).get('v');
  if (videoId) {
    return {source: 'constructed', url: 'https://img.youtube.com/vi/' + videoId + '/maxresdefault.jpg'};
  }
  return null;
})()
